/**********************************
变量定义
**********************************/
uint8_t  key_num = 0;                  // 按键扫描标志位
uint8_t  flag_display = 0;             // 显示界面标志位
uint32_t time_num = 0;                 // 10ms计时

uint16_t temp_value = 0;               // 温度值（放大10倍）
uint16_t humi_value = 0;               // 湿度值（放大10倍）

uint16_t temp_max = 40;                // 温度最大值
uint16_t temp_min = 20;                // 温度最小值
uint16_t humi_max = 80;                // 湿度最大值
uint16_t humi_min = 40;                // 湿度最小值

float    temp1_value = 0;              // 红外体温值
uint16_t temp1_max = 38;               // 体温最大值

_Bool flag_mode = 0;                   // 0=自动 1=手动
uint8_t flag_num = 0;                  // 主界面选项：0模式 1加热 2散热 3加湿

uint8_t urine_alarm = 0;               // 尿床报警：0正常 1报警
uint8_t temp1_alarm = 0;               // 体温报警：0正常 1报警
uint8_t alarm_flag = 0;                // 综合报警标志：0正常 1报警

char display_buf[64];                  // OLED显示缓存
char send_data[512];                   // 阿里云发送数组
const char *topics_set[] = {"/sys/a1BV0wUk1zM/yejk01/thing/service/property/set"};
const char *topics_post = "/sys/a1BV0wUk1zM/yejk01/thing/event/property/post";
uint8_t *dataPtr = NULL;               // 设备返回数据
uint8_t *receive_data = NULL;          // 云端下发数据
char *result = NULL;                   // 结果指针

/* 上传调度相关 */
uint8_t  flag_report_dirty = 1;        // 状态有变化，需要上报
uint16_t report_holdoff_cnt = 0;       // 下发后延迟上传计数，单位10ms


/**********************************
函数声明
**********************************/
void Key_function(void);               // 按键函数
void Monitor_function(void);           // 监测函数
void Display_function(void);           // 显示函数
void Manage_function(void);            // 处理函数
void Alarm_Function(void);             // 声光报警函数
void Aliyun_Send_Data(void);           // 阿里云数据上报函数

static void All_Output_Off(void);
static uint8_t Json_GetInt(char *src, const char *key, int *value);
static void Cloud_Parse_Function(void);
static void Report_Task(void);
static int16_t Temp1_To10(void);


/****
******* 主函数
*****/
int main(void)
{
    NVIC_PriorityGroupConfig(NVIC_PriorityGroup_2);   // 配置中断优先级分组
    Delay_Init();                                     // 延时初始化
    Gpio_Init();                                      // IO初始化
    Key_Init();                                       // 按键初始化
    Oled_Init();                                      // OLED初始化
    Oled_Clear_All();                                 // 清屏
    Usart1_Init(9600);                                // 串口1初始化
    Delay_ms(500);
    Usart2_Init(115200);                              // 串口2初始化
    TIM3_Init(9, 7199);                               // 定时器初始化

    MLX90614_SMBus_Init();                            // 红外测温初始化
    Delay_ms(50);

    All_Output_Off();
    BEEP = 0;                                         // 关闭蜂鸣器
    ALARM_LED = 1;                                    // 关闭红灯（低电平点亮，所以1为灭）

    Oled_ShowString(1, 6, "DHT11");
    Oled_ShowCHinese(2, 2, "初始化中");
    while(DHT11_Init());                              // DHT11初始化

    Oled_ShowString(1, 6, "WIFI ");
    Oled_ShowCHinese(2, 2, "初始化中");
    ESP8266_Init();                                   // ESP8266初始化

    while(Aliyun_DevLink())                           // 接入阿里云
    {
        Delay_ms(500);
    }

    Aliyun_Subscribe(topics_set, 1);                  // 订阅云端下发主题
    Oled_Clear_All();

    while(1)
    {
        Key_function();                               // 按键处理
        Monitor_function();                           // 传感器、尿床、云端下发
        Manage_function();                            // 自动/手动控制
        Alarm_Function();                             // 声光报警处理
        Report_Task();                                // 上传调度
        Display_function();                           // OLED显示

        time_num++;
        if(time_num % 50 == 0)                        // 约500ms闪烁一次
        {
            LED_SYS = ~LED_SYS;
        }

        if(time_num >= 5000)
        {
            time_num = 0;
        }

        Delay_ms(10);                                 // 主循环10ms
    }
}

/****
******* 关闭全部执行器
*****/
static void All_Output_Off(void)
{
    RELAY_JR = 0;     // 加热关闭
    RELAY_SR = 0;     // 散热关闭
    RELAY_JS = 0;     // 加湿关闭
}


/****
******* 红外体温值转放大10倍整数
*****/
static int16_t Temp1_To10(void)
{
    if(temp1_value >= 0)
        return (int16_t)(temp1_value + 0.5f);
    else
        return (int16_t)(temp1_value - 0.5f);
}


/****
******* 简单JSON整数解析
******* 例如解析 "temp_max":40
*****/
static uint8_t Json_GetInt(char *src, const char *key, int *value)
{
    char *p = NULL;

    if(src == NULL || key == NULL || value == NULL)
        return 0;

    p = strstr(src, key);
    if(p == NULL)
        return 0;

    p = strstr(p, ":");
    if(p == NULL)
        return 0;

    p += 1;
    *value = atoi(p);
    return 1;
}

static void Cloud_Parse_Function(void)
{
    int value = 0;
    uint8_t cloud_changed = 0;

    if(receive_data == NULL)
        return;

    /* 模式 */
    if(Json_GetInt((char *)receive_data, "flag_mode", &value))
    {
        flag_mode = (_Bool)value;
        All_Output_Off();
        cloud_changed = 1;
    }

    /* 温度最大值 */
    if(Json_GetInt((char *)receive_data, "temp_max", &value))
    {
        if(value < 0) value = 0;
        if(value > 99) value = 99;
        temp_max = (uint16_t)value;

        if(temp_max <= temp_min)
        {
            if(temp_min < 99)
                temp_max = temp_min + 1;
            else
            {
                temp_min = 98;
                temp_max = 99;
            }
        }
        cloud_changed = 1;
    }

    /* 温度最小值 */
    if(Json_GetInt((char *)receive_data, "temp_min", &value))
    {
        if(value < 0) value = 0;
        if(value > 99) value = 99;
        temp_min = (uint16_t)value;

        if(temp_min >= temp_max)
        {
            if(temp_max > 0)
                temp_min = temp_max - 1;
            else
            {
                temp_min = 0;
                temp_max = 1;
            }
        }
        cloud_changed = 1;
    }

    /* 湿度最大值 */
    if(Json_GetInt((char *)receive_data, "humi_max", &value))
    {
        if(value < 0) value = 0;
        if(value > 99) value = 99;
        humi_max = (uint16_t)value;

        if(humi_max <= humi_min)
        {
            if(humi_min < 99)
                humi_max = humi_min + 1;
            else
            {
                humi_min = 98;
                humi_max = 99;
            }
        }
        cloud_changed = 1;
    }

    /* 湿度最小值 */
    if(Json_GetInt((char *)receive_data, "humi_min", &value))
    {
        if(value < 0) value = 0;
        if(value > 99) value = 99;
        humi_min = (uint16_t)value;

        if(humi_min >= humi_max)
        {
            if(humi_max > 0)
                humi_min = humi_max - 1;
            else
            {
                humi_min = 0;
                humi_max = 1;
            }
        }
        cloud_changed = 1;
    }

    /* 体温最大值 */
    if(Json_GetInt((char *)receive_data, "temp1_max", &value))
    {
        if(value < 0) value = 0;
        if(value > 99) value = 99;
        temp1_max = (uint16_t)value;
        cloud_changed = 1;
    }

    /* 云端手动控制加热 */
    if(Json_GetInt((char *)receive_data, "RELAY_JR", &value))
    {
        flag_mode = 1;

        if(value != 0)
        {
            RELAY_JR = 1;
            RELAY_SR = 0;   // 加热和散热互斥
        }
        else
        {
            RELAY_JR = 0;
        }
        cloud_changed = 1;
    }

    /* 云端手动控制散热/通风 */
    if(Json_GetInt((char *)receive_data, "RELAY_SR", &value))
    {
        flag_mode = 1;

        if(value != 0)
        {
            RELAY_SR = 1;
            RELAY_JR = 0;   // 散热和加热互斥
        }
        else
        {
            RELAY_SR = 0;
        }
        cloud_changed = 1;
    }

    /* 云端手动控制加湿 */
    if(Json_GetInt((char *)receive_data, "RELAY_JS", &value))
    {
        flag_mode = 1;
        RELAY_JS = (value != 0) ? 1 : 0;
        cloud_changed = 1;
    }

    if(cloud_changed == 1)
    {
        flag_report_dirty = 1;
        report_holdoff_cnt = 30;   // 300ms内先不主动上报，避免和下发打架
    }

    MQTT_FreeBuffer(receive_data);
    receive_data = NULL;
}


/****
******* 按键函数
******* 按键1：切换页面
******* 按键2：
*******   主页面：手动模式下切换选项（模式/加热/散热/加湿）
*******   设置页面：数值加
******* 按键3：
*******   主页面：执行当前选项
*******   设置页面：数值减

void Key_function(void)
{
    uint8_t local_changed = 0;

    key_num = Chiclet_Keyboard_Scan(0);
    if(key_num != 0)
    {
        switch(key_num)
        {
            case 1:
                flag_display++;
                if(flag_display >= 6)
                    flag_display = 0;

                Oled_Clear_All();
            break;

            case 2:
                switch(flag_display)
                {
                    case 0:
                        if(flag_mode == 1)   // 保留你原来的逻辑：只有手动模式才能切换控制对象
                        {
                            flag_num++;
                            if(flag_num >= 4)
                                flag_num = 0;
                        }
                    break;

                    case 1:     // temp_max++
                        if(temp_max < 99)
                        {
                            temp_max++;
                            if(temp_max <= temp_min)
                                temp_max = temp_min + 1;
                            local_changed = 1;
                        }
                    break;

                    case 2:     // temp_min++
                        if(temp_min < 99)
                        {
                            temp_min++;
                            if(temp_min >= temp_max)
                                temp_min = temp_max - 1;
                            local_changed = 1;
                        }
                    break;

                    case 3:     // humi_max++
                        if(humi_max < 99)
                        {
                            humi_max++;
                            if(humi_max <= humi_min)
                                humi_max = humi_min + 1;
                            local_changed = 1;
                        }
                    break;

                    case 4:     // humi_min++
                        if(humi_min < 99)
                        {
                            humi_min++;
                            if(humi_min >= humi_max)
                                humi_min = humi_max - 1;
                            local_changed = 1;
                        }
                    break;

                    case 5:     // temp1_max++
                        if(temp1_max < 99)
                        {
                            temp1_max++;
                            local_changed = 1;
                        }
                    break;

                    default:
                    break;
                }
            break;

            case 3:
                switch(flag_display)
                {
                    case 0:
                        switch(flag_num)
                        {
                            case 0:     // 模式切换
                                flag_mode = !flag_mode;
                                All_Output_Off();
                                local_changed = 1;
                            break;

                            case 1:     // 手动控制加热
                                if(flag_mode == 1)
                                {
                                    if(RELAY_JR == 0)
                                    {
                                        RELAY_JR = 1;
                                        RELAY_SR = 0;   // 加热和散热互斥
                                    }
                                    else
                                    {
                                        RELAY_JR = 0;
                                    }
                                    local_changed = 1;
                                }
                            break;

                            case 2:     // 手动控制散热
                                if(flag_mode == 1)
                                {
                                    if(RELAY_SR == 0)
                                    {
                                        RELAY_SR = 1;
                                        RELAY_JR = 0;   // 散热和加热互斥
                                    }
                                    else
                                    {
                                        RELAY_SR = 0;
                                    }
                                    local_changed = 1;
                                }
                            break;

                            case 3:     // 手动控制加湿
                                if(flag_mode == 1)
                                {
                                    RELAY_JS = !RELAY_JS;
                                    local_changed = 1;
                                }
                            break;

                            default:
                            break;
                        }
                    break;

                    case 1:     // temp_max--
                        if(temp_max > 1)
                        {
                            temp_max--;
                            if(temp_max <= temp_min)
                                temp_max = temp_min + 1;
                            local_changed = 1;
                        }
                    break;

                    case 2:     // temp_min--
                        if(temp_min > 0)
                        {
                            temp_min--;
                            local_changed = 1;
                        }
                    break;

                    case 3:     // humi_max--
                        if(humi_max > 1)
                        {
                            humi_max--;
                            if(humi_max <= humi_min)
                                humi_max = humi_min + 1;
                            local_changed = 1;
                        }
                    break;

                    case 4:     // humi_min--
                        if(humi_min > 0)
                        {
                            humi_min--;
                            local_changed = 1;
                        }
                    break;

                    case 5:     // temp1_max--
                        if(temp1_max > 0)
                        {
                            temp1_max--;
                            local_changed = 1;
                        }
                    break;

                    default:
                    break;
                }
            break;

            default:
            break;
        }
    }

    if(local_changed == 1)
    {
        flag_report_dirty = 1;
    }
}


/****
******* 监测函数
******* 1. 读取温湿度
******* 2. 读取红外温度
******* 3. 检测尿床
******* 4. 体温超限判断
******* 5. 接收云端下发
*****/
void Monitor_function(void)
{
    static uint16_t dht_cnt = 0;
    static uint16_t mlx_cnt = 0;

    /* 尿床检测：默认NC=0表示报警 */
    if(NC == 0)
        urine_alarm = 1;
    else
        urine_alarm = 0;

    /* 每50ms读取一次DHT11 */
    dht_cnt++;
    if(dht_cnt >= 5)
    {
        dht_cnt = 0;
        Dht11_Get_Temp_Humi_Value(&temp_value, &humi_value);
    }

    /* 每30ms读取一次红外测温 */
    mlx_cnt++;
    if(mlx_cnt >= 3)
    {
        mlx_cnt = 0;
        temp1_value = MLX90614_SMBus_ReadTemp();
    }

    /* 体温超限报警 */
    if(Temp1_To10() >= (int16_t)(temp1_max * 10))
        temp1_alarm = 1;
    else
        temp1_alarm = 0;

    /* 综合报警 */
    if((urine_alarm == 1) || (temp1_alarm == 1))
        alarm_flag = 1;
    else
        alarm_flag = 0;

    /* 接收阿里云下发数据 */
    dataPtr = ESP8266_GetIPD(0);
    if(dataPtr != NULL)
    {
        Aliyun_RevPro(dataPtr);
        Cloud_Parse_Function();
    }
}

void Alarm_Function(void)
{
    static uint8_t alarm_flash_state = 0;
    static uint16_t alarm_flash_cnt = 0;

    if(alarm_flag == 1)
    {
        alarm_flash_cnt++;
        if(alarm_flash_cnt >= 20)      // 200ms翻转一次
        {
            alarm_flash_cnt = 0;
            alarm_flash_state = !alarm_flash_state;
        }

        if(alarm_flash_state == 0)
        {
            BEEP = 1;                  // 蜂鸣器响
            ALARM_LED = 0;             // 红灯亮（低电平点亮）
        }
        else
        {
            BEEP = 0;                  // 蜂鸣器关
            ALARM_LED = 1;             // 红灯灭
        }
    }
    else
    {
        alarm_flash_cnt = 0;
        alarm_flash_state = 0;
        BEEP = 0;                      // 关闭蜂鸣器
        ALARM_LED = 1;                 // 关闭红灯
    }
}

void Manage_function(void)
{
    uint8_t old_jr = RELAY_JR;
    uint8_t old_sr = RELAY_SR;
    uint8_t old_js = RELAY_JS;

    if(flag_mode == 0)     // 自动模式
    {
        /* 温度低于最小值 -> 加热 */
        if(temp_value < temp_min * 10)
        {
            RELAY_JR = 1;
        }
        else
        {
            RELAY_JR = 0;
        }

        /* 湿度低于最小值 -> 加湿 */
        if(humi_value < humi_min * 10)
        {
            RELAY_JS = 1;
        }
        else
        {
            RELAY_JS = 0;
        }

        /* 温度高于最大值 或 湿度高于最大值 -> 散热/通风 */
        if((temp_value > temp_max * 10) || (humi_value > humi_max * 10))
        {
            RELAY_SR = 1;
            RELAY_JR = 0;   // 散热时关闭加热，避免冲突
        }
        else
        {
            RELAY_SR = 0;
        }
    }
    else
    {
        /* 手动模式下，不覆盖按键/云端设置的状态 */
    }

    /* 自动控制导致输出状态变化，也需要上报 */
    if((old_jr != RELAY_JR) || (old_sr != RELAY_SR) || (old_js != RELAY_JS))
    {
        flag_report_dirty = 1;
    }
}


/****
******* 上传调度任务
******* 有变化时，最快200ms上报一次
******* 无变化时，500ms保活上报一次
******* 云端刚下发后，先抑制300ms上传，避免冲突
*****/
static void Report_Task(void)
{
    static uint16_t fast_cnt = 0;
    static uint16_t keepalive_cnt = 0;
    static uint8_t first_send = 1;

    static uint16_t last_temp_value = 0xFFFF;
    static uint16_t last_humi_value = 0xFFFF;
    static int16_t  last_temp1_value = 0x7FFF;
    static uint16_t last_temp_max = 0xFFFF;
    static uint16_t last_temp_min = 0xFFFF;
    static uint16_t last_humi_max = 0xFFFF;
    static uint16_t last_humi_min = 0xFFFF;
    static uint16_t last_temp1_max = 0xFFFF;
    static uint8_t  last_flag_mode = 0xFF;
    static uint8_t  last_relay_jr = 0xFF;
    static uint8_t  last_relay_sr = 0xFF;
    static uint8_t  last_relay_js = 0xFF;
    static uint8_t  last_urine_alarm = 0xFF;

    int16_t temp1_now = Temp1_To10();
    uint8_t snapshot_changed = 0;

    if(fast_cnt < 0xFFFF)      fast_cnt++;
    if(keepalive_cnt < 0xFFFF) keepalive_cnt++;

    if((last_temp_value  != temp_value)   ||
       (last_humi_value  != humi_value)   ||
       (last_temp1_value != temp1_now)    ||
       (last_temp_max    != temp_max)     ||
       (last_temp_min    != temp_min)     ||
       (last_humi_max    != humi_max)     ||
       (last_humi_min    != humi_min)     ||
       (last_temp1_max   != temp1_max)    ||
       (last_flag_mode   != flag_mode)    ||
       (last_relay_jr    != RELAY_JR)     ||
       (last_relay_sr    != RELAY_SR)     ||
       (last_relay_js    != RELAY_JS)     ||
       (last_urine_alarm != urine_alarm))
    {
        snapshot_changed = 1;
        flag_report_dirty = 1;
    }

    /* 下发后短时间内不主动上传，避免和手机端/云端冲突 */
    if(report_holdoff_cnt > 0)
    {
        report_holdoff_cnt--;
        return;
    }

    /* 有变化时，最快200ms上报一次 */
    if((flag_report_dirty == 1 || first_send == 1 || snapshot_changed == 1) && (fast_cnt >= 20))
    {
        Aliyun_Send_Data();

        last_temp_value  = temp_value;
        last_humi_value  = humi_value;
        last_temp1_value = temp1_now;
        last_temp_max    = temp_max;
        last_temp_min    = temp_min;
        last_humi_max    = humi_max;
        last_humi_min    = humi_min;
        last_temp1_max   = temp1_max;
        last_flag_mode   = flag_mode;
        last_relay_jr    = RELAY_JR;
        last_relay_sr    = RELAY_SR;
        last_relay_js    = RELAY_JS;
        last_urine_alarm = urine_alarm;

        flag_report_dirty = 0;
        first_send = 0;
        fast_cnt = 0;
        keepalive_cnt = 0;
        return;
    }

    /* 无变化时，500ms保活上报一次 */
    if(keepalive_cnt >= 50)
    {
        Aliyun_Send_Data();

        last_temp_value  = temp_value;
        last_humi_value  = humi_value;
        last_temp1_value = temp1_now;
        last_temp_max    = temp_max;
        last_temp_min    = temp_min;
        last_humi_max    = humi_max;
        last_humi_min    = humi_min;
        last_temp1_max   = temp1_max;
        last_flag_mode   = flag_mode;
        last_relay_jr    = RELAY_JR;
        last_relay_sr    = RELAY_SR;
        last_relay_js    = RELAY_JS;
        last_urine_alarm = urine_alarm;

        flag_report_dirty = 0;
        first_send = 0;
        fast_cnt = 0;
        keepalive_cnt = 0;
    }
}


/****
