/****
******* 按键处理函数
mode:0,不支持连续按;1,支持连续按;
*****/
u8 Chiclet_Keyboard_Scan(u8 mode)
{
    static u8 key_up=1;         //按键松开标志

    if(mode)                            //mode=1,支持连按
        key_up=1;

    if(key_up && (KEY1==0||KEY2==0||KEY3==0))
    {
        Delay_ms(10);                   //去抖动
        key_up=0;

        if(KEY1==0)                     //按键1按下，返回1
            return 1;
        else if(KEY2==0)            //按键2按下，返回2
            return 2;
        else if(KEY3==0)            //按键3按下，返回3
            return 3;
    }
    else if(KEY1==1&&KEY2==1&&KEY3==1)      //没有按键按下，松开标志位置1
    {
        key_up=1;
    }

    return 0;                               // 无按键按下.返回0
}

#include "timer.h"

/*
 main里调用示例：
 TIM3_Init(9, 7199);
*/

_Bool flag_timer_begin_1s = 0;   // 1秒计时开始标志位
_Bool flag_1s = 0;               // 1秒完成标志位

_Bool flag_timer_begin_2s = 0;   // 2秒计时开始标志位
_Bool flag_2s = 0;               // 2秒完成标志位

void TIM3_Init(u16 arr, u16 psc)
{
    TIM_TimeBaseInitTypeDef TIM_TimeBaseStructure;
    NVIC_InitTypeDef NVIC_InitStructure;

    // TIM3 在 APB1 上
    RCC_APB1PeriphClockCmd(RCC_APB1Periph_TIM3, ENABLE);

    // 定时器初始化
    TIM_TimeBaseStructure.TIM_Period = arr;
    TIM_TimeBaseStructure.TIM_Prescaler = psc;
    TIM_TimeBaseStructure.TIM_ClockDivision = TIM_CKD_DIV1;
    TIM_TimeBaseStructure.TIM_CounterMode = TIM_CounterMode_Up;
    TIM_TimeBaseInit(TIM3, &TIM_TimeBaseStructure);

    // 允许更新中断
    TIM_ITConfig(TIM3, TIM_IT_Update, ENABLE);

    // NVIC 配置：TIM3 的中断通道
    NVIC_InitStructure.NVIC_IRQChannel = TIM3_IRQn;
    NVIC_InitStructure.NVIC_IRQChannelPreemptionPriority = 0;
    NVIC_InitStructure.NVIC_IRQChannelSubPriority = 3;
    NVIC_InitStructure.NVIC_IRQChannelCmd = ENABLE;
    NVIC_Init(&NVIC_InitStructure);

    // 启动定时器
    TIM_Cmd(TIM3, ENABLE);
}

// TIM3 中断服务函数
void TIM3_IRQHandler(void)
{
    static uint16_t time_value_1s = 0;
    static uint16_t time_value_2s = 0;

    if (TIM_GetITStatus(TIM3, TIM_IT_Update) != RESET)
    {
        TIM_ClearITPendingBit(TIM3, TIM_IT_Update);

        /************** 1秒计时 **************/
        if (flag_timer_begin_1s == 1)
        {
            time_value_1s++;
            if (time_value_1s >= 1000)   // 1s
            {
                time_value_1s = 0;
                flag_1s = 1;
            }
        }
        else
        {
            time_value_1s = 0;
            flag_1s = 0;
        }

        /************** 2秒计时 **************/
        if (flag_timer_begin_2s == 1)
        {
            time_value_2s++;
            if (time_value_2s >= 2500)   // 2s
            {
                time_value_2s = 0;
                flag_2s = 1;
            }
        }
        else
        {
            time_value_2s = 0;
            flag_2s = 0;
        }
    }
}
